class Solution {
    long long ans = 0;
    void mergeCount(vector<long long>& v, int l, int m, int r, int lo, int hi) {
        int j = m+1, k = m+1;
        for (int i = l; i <= m; i++) {
            while (j <= r && v[j] < v[i] + lo) j++;
            while (k <= r && v[k] <= v[i] + hi) k++;
            ans += k - j;
        }
        inplace_merge(v.begin()+l, v.begin()+m+1, v.begin()+r+1);
    }
    void sort(vector<long long>& v, int l, int r, int lo, int hi) {
        if (l >= r) return;
        int m = (l + r) / 2;
        sort(v, l, m, lo, hi); sort(v, m+1, r, lo, hi);
        mergeCount(v, l, m, r, lo, hi);
    }
public:
    int countRangeSum(vector<int>& nums, int lower, int upper) {
        vector<long long> pre = {0};
        for (int x : nums) pre.push_back(pre.back() + x);
        sort(pre, 0, pre.size()-1, lower, upper);
        return (int)ans;
    }
};

